DEBUG = 1
VERSION = '1.5'

class LegacyNode:
    def __init__(self, name, children=None):
        self.name = name
        self.children = children or []

    def add(self, node):
        self.children.append(node)
        return self

    def dump(self):
        print `self.name`
        for child in self.children:
            print `child.name`


def legacy_apply(fn, args, kwargs=None):
    if kwargs:
        return apply(fn, args, kwargs)
    return apply(fn, args)


def legacy_exec_block(code, env):
    exec code in env


